class Solution:
    def maximumLength(self, s: str) -> int:
        max_len = -1
        for i in range(len(s)):
            count = 1
            for j in range(i + 1, len(s)):
                if s[j] == s[i]:
                    count += 1
                else:
                    break
            if count >= 3:
                max_len = max(max_len, count)
        return max_len
